for chap_num, ext_text in extensions.items():
    file_path = os.path.join(chapter_dir, f"chapter_{chap_num}.txt")
    if os.path.exists(file_path):
        with open(file_path, "r", encoding="utf-8") as f:
            content = f.read()
        
        # Overwrite with clean concatenation
        new_content = content + ext_text
        with open(file_path, "w", encoding="utf-8") as f:
            f.write(new_content)
        print(f"Chapter {chap_num} expanded to: {len(new_content)}")

print("Clean Expansion completed!")
